// portfolio.js
// Caching moved to window.globalAssetCache.portfolio in config.js

const getPortfolioCategories = () => {
    const defaultCategories = [
        { title: 'Portraits', image: 'data:image/jpeg;base64,' },
        { title: 'Pre Weddings', image: 'data:image/jpeg;base64,' },
        { title: 'Weddings', image: 'data:image/jpeg;base64,' },
        { title: 'Reception', image: 'data:image/jpeg;base64,' },
        { title: 'Model Shoot', image: '.data:image/jpeg;base64,' },
        { title: 'Engagement', image: 'data:image/jpeg;base64,' }
    ];

    return defaultCategories.map((cat, idx) => ({ ...cat, link: `#portfolio-${idx}` }));
};

let PORTFOLIO_CATEGORIES = getPortfolioCategories();

function PortfolioCard({ item, idx }) {
    if (!item) return null;
    const cardStyles = {
        card: {
            borderRadius: "32px",
            background: 'linear-gradient(135deg, #c961e6 0%, #6f25e9 100%)',
            padding: '2.5px',
            overflow: "hidden",
            cursor: "pointer",
            transform: "translateZ(0)",
            transition: "transform 0.8s cubic-bezier(0.16, 1, 0.3, 1)",
            willChange: "transform",
            display: 'block',
            textDecoration: 'none',
            position: 'relative'
        },
        inner: {
            borderRadius: "30px",
            overflow: "hidden",
            position: 'relative',
            width: '100%',
            height: '100%',
            backgroundColor: '#000'
        },
        image: {
            width: "100%",
            height: "100%",
            display: "block",
            objectFit: 'cover',
            transition: "transform 1.2s cubic-bezier(0.16, 1, 0.3, 1)",
            willChange: "transform"
        },
        overlay: {
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            background: 'rgba(0,0,0,0.35)', // Darker overlay as requested in image
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 2,
            transition: 'background 0.3s ease'
        },
        title: {
            color: '#ffffff',
            fontSize: 'clamp(1.5rem, 3.5vw, 2.5rem)',
            fontWeight: '700',
            letterSpacing: '-0.5px',
            textAlign: 'center',
            textShadow: '0 2px 10px rgba(0,0,0,0.5)'
        }
    };

    return el('a', {
        href: item.link,
        className: 'portfolio-card',
        style: cardStyles.card,
        onMouseEnter: (e) => {
            const overlay = e.currentTarget.querySelector('.card-overlay');
            if (overlay) overlay.style.background = 'rgba(0,0,0,0.4)';
        },
        onMouseLeave: (e) => {
            const overlay = e.currentTarget.querySelector('.card-overlay');
            if (overlay) overlay.style.background = 'linear-gradient(to bottom, rgba(0,0,0,0.1), rgba(0,0,0,0.6))';
        }
    },
        el('div', { style: cardStyles.inner },
            el('img', {
                src: item.image,
                alt: item.title,
                style: cardStyles.image
            }),
            el('div', { className: 'card-overlay', style: cardStyles.overlay },
                el(Reveal, { animation: 'fade-up' },
                    el('h3', { style: cardStyles.title }, item.title)
                )
            )
        )
    );
}
function PortfolioPage({ onBack }) {
    const [portfolio, setPortfolio] = React.useState(() => getPortfolioCategories());
    const containerRef = React.useRef(null);
    const heroTextRef = React.useRef(null);

    React.useLayoutEffect(() => {
        window.scrollTo(0, 0);
        if (window.lenis) window.lenis.scrollTo(0, { immediate: true });
    }, []);

    React.useEffect(() => {
        const initialCategories = getPortfolioCategories(); // Re-fetch to ensure latest for pre-fetching
        // Pre-fetch all categories for instant in-memory loading (<0.02s)
        initialCategories.forEach(cat => {
            if (!window.globalAssetCache.portfolio[cat.title]) {
                fetch(`${window.API_URL}/api/portfolio/${encodeURIComponent(cat.title)}`)
                    .then(res => res.json())
                    .then(data => {
                        if (Array.isArray(data)) {
                            window.globalAssetCache.portfolio[cat.title] = data;
                            data.forEach(url => {
                                const img = new Image();
                                img.src = url;
                            });
                        }
                    })
                    .catch(err => console.error(`Pre-fetch error for ${cat.title}:`, err));
            }
        });
    }, []);

    // 🍎 Apple Butter-flow Animation System (GSAP + RAF)
    React.useEffect(() => {
        let rafId;

        const update = () => {
            const cards = document.querySelectorAll(".portfolio-card");
            const windowH = window.innerHeight;

            cards.forEach((card) => {
                if (!card) return;
                const rect = card.getBoundingClientRect();

                // Only calculate/update if visible or close to viewport
                if (rect.top < windowH * 1.5 && rect.bottom > -windowH * 0.5) {
                    const center = rect.top + rect.height / 2;
                    const distance = center - windowH / 2;
                    const progress = distance / windowH;

                    // Cinematic scaling & Vertical drift (Direct Set for 0ms lag)
                    const targetScale = 1 - Math.abs(progress) * 0.15;
                    const targetY = progress * -40;

                    gsap.set(card, {
                        scale: Math.max(targetScale, 0.85),
                        y: targetY,
                        force3D: true // Ensure GPU acceleration
                    });

                    // Soft parallax for internal photography
                    const img = card.querySelector('img');
                    if (img) {
                        gsap.set(img, {
                            y: progress * 60,
                            scale: 1.1,
                            force3D: true
                        });
                    }
                }
            });

            rafId = requestAnimationFrame(update);
        };

        rafId = requestAnimationFrame(update);
        return () => cancelAnimationFrame(rafId);
    }, []);

    // Cinematic Intro from Home Page
    React.useEffect(() => {
        if (heroTextRef.current && typeof gsap !== 'undefined') {
            gsap.fromTo(heroTextRef.current.children,
                { opacity: 0, y: 40 },
                {
                    opacity: 1,
                    y: 0,
                    duration: 1.4,
                    stagger: 0.15,
                    ease: "power3.out",
                    delay: 0.3
                }
            );
        }
    }, []);

    const styles = {
        wrapper: {
            background: "#ffffff",
            fontFamily: "-apple-system, BlinkMacSystemFont, 'SF Pro Display', sans-serif",
            color: "#111",
            minHeight: "100vh"
        },
        hero: {
            padding: "160px 8% 100px",
            // height: "60vh",
            display: "flex",
            flexDirection: "column",
            justifyContent: "center",
            textAlign: 'center',
            alignItems: 'center'
        },
        title: {
            fontSize: "clamp(3.5rem, 8vw, 6rem)",
            fontWeight: 700,
            letterSpacing: "-2px",
            lineHeight: "1",
            marginBottom: "1.5rem"
        },
        subtitle: {
            fontSize: "1.2rem",
            color: "#666",
            maxWidth: "900px",
            lineHeight: "1.6",
            margin: '0 auto'
        },
        grid: {
            display: "grid",
            gap: "24px",
            padding: "0 6% 120px",
            maxWidth: "2000px",
            margin: "0 auto"
        }
    };

    return el('div', { style: styles.wrapper, ref: containerRef },
        el('section', { style: styles.hero },
            el('div', { ref: heroTextRef, style: { willChange: 'transform, opacity', width: '100%' } },
                el(AppleTextReveal, { text: 'Our Portfolio', style: styles.title }),
                el(Reveal, { animation: 'fade-up', delay: 200 },
                    el('p', { style: { ...styles.subtitle, marginBottom: '0.5rem' } }, 'At Kavithaigal Studio, every frame is a scene, every moment a story.'),
                    el('p', { style: styles.subtitle }, 'From pre-wedding dreams to wedding vows, receptions, engagements, portraits, and cinematic films we capture emotions as they unfold naturally.')
                )
            )
        ),

        el('section', { className: 'portfolio-grid', style: styles.grid },
            portfolio.map((item, idx) => (
                el(PortfolioCard, { key: idx, item: item, idx: idx })
            ))
        )
    );
}


function PortfolioCategoryPage({ categoryIdx }) {
    const bannerImageRef = React.useRef(null);
    const bannerTextRef = React.useRef(null);
    const [activeImageIndex, setActiveImageIndex] = React.useState(null);

    // Get fresh categories from localStorage inside the component
    const freshCategories = getPortfolioCategories();
    const category = freshCategories[categoryIdx];
    const categoryName = category ? category.title : '';

    React.useLayoutEffect(() => {
        // Immediate scroll to top before paint
        window.scrollTo(0, 0);
        if (window.lenis) window.lenis.scrollTo(0, { immediate: true });
    }, []);

    const [masonryImages, setMasonryImages] = React.useState(window.globalAssetCache.portfolio[categoryName] || []);

    React.useEffect(() => {
        if (categoryName) {
            // If already in cache (from pre-fetch), we're done
            if (window.globalAssetCache.portfolio[categoryName] && window.globalAssetCache.portfolio[categoryName].length > 0) {
                setMasonryImages(window.globalAssetCache.portfolio[categoryName]);
                return;
            }

            fetch(`${window.API_URL}/api/portfolio/${encodeURIComponent(categoryName)}`)
                .then(res => res.json())
                .then(data => {
                    if (Array.isArray(data)) {
                        setMasonryImages(data);
                        window.globalAssetCache.portfolio[categoryName] = data;
                    }
                })
                .catch(err => console.error('Error fetching portfolio categories:', err));
        }
    }, [categoryName]);

    // Banner Intro
    React.useEffect(() => {
        if (bannerTextRef.current && typeof gsap !== 'undefined') {
            gsap.fromTo(bannerTextRef.current.children,
                { opacity: 0, y: 40 },
                {
                    opacity: 1,
                    y: 0,
                    duration: 1.2,
                    stagger: 0.1,
                    ease: "power2.out",
                    delay: 0.1
                }
            );
        }
    }, []);

    return el('div', { className: 'category-page-container' },
        el('div', { className: 'inner-banner-wrapper' },
            el('img', {
                ref: bannerImageRef,
                className: 'inner-banner-image',
                src: category ? category.image : '',
                alt: categoryName,
                style: { transform: 'scale(1.0) translateZ(0)', width: '100%', height: '100%', objectFit: 'cover' }
            }),
            el('div', { className: 'inner-banner-overlay' },
                el('div', { ref: bannerTextRef, style: { width: '100%', textAlign: 'center' } },
                    el(AppleTextReveal, { text: categoryName, style: { color: '#fff', marginBottom: '1rem' } }),
                    el(Reveal, { animation: 'fade-up', delay: 300 },
                        el('p', { className: 'inner-banner-subtitle' }, 'Moments that matter, memories that stay.')
                    )
                )
            )
        ),

        el('div', { className: 'category-content' },
            el('div', { className: 'fancy-masonry-grid' },
                masonryImages.map((src, idx) =>
                    el(Reveal, { key: idx, animation: 'zoom-in', delay: (idx % 6) * 100 },
                        el('div', {
                            className: `fancy-masonry-item item-${idx}`,
                            onClick: () => setActiveImageIndex(idx),
                            style: { cursor: 'pointer' }
                        },
                            el('img', { src: src, alt: `Gallery image ${idx + 1}` })
                        )
                    )
                )
            ),
            el(BookShootCTA, { titlePart2: ` to book your ${categoryName.toLowerCase()}?` })
        ),

        activeImageIndex !== null && el(Lightbox, {
            images: masonryImages,
            activeIndex: activeImageIndex,
            onClose: () => setActiveImageIndex(null),
            onNext: () => setActiveImageIndex((prev) => (prev + 1) % masonryImages.length),
            onPrev: () => setActiveImageIndex((prev) => (prev - 1 + masonryImages.length) % masonryImages.length)
        })
    );
}

function ExploreWorkInnerPage({ card, onBack }) {
    const bannerImageRef = React.useRef(null);
    const bannerTextRef = React.useRef(null);

    React.useEffect(() => {
        window.scrollTo(0, 0);
    }, []);

    const [activeImageIndex, setActiveImageIndex] = React.useState(null);

    const [galleryImages, setGalleryImages] = React.useState([]);

    React.useEffect(() => {
        if (card.title) {
            fetch(`${window.API_URL}/api/inner-images/${encodeURIComponent(card.title)}`)
                .then(res => res.json())
                .then(data => {
                    if (Array.isArray(data)) setGalleryImages(data);
                })
                .catch(err => console.error('Error fetching inner gallery:', err));
        }
    }, [card.title]);

    // Parallax Logic Removed
    React.useEffect(() => {
        if (bannerImageRef.current) {
            bannerImageRef.current.style.transform = 'translateZ(0) scale(1.0)';
        }
    }, []);

    // Intro Logic
    React.useEffect(() => {
        if (bannerTextRef.current && typeof gsap !== 'undefined') {
            gsap.fromTo(bannerTextRef.current.children,
                { opacity: 0, y: 40 },
                {
                    opacity: 1,
                    y: 0,
                    duration: 1.2,
                    stagger: 0.1,
                    ease: "power2.out",
                    delay: 0.1
                }
            );
        }
    }, []);

    return el('div', { className: 'inner-page-container' },
        el('div', { className: 'inner-banner-wrapper' },
            el('img', {
                ref: bannerImageRef,
                className: 'inner-banner-image',
                src: card.image,
                alt: card.title,
                style: { transform: 'scale(1.0) translateZ(0)', width: '100%', height: '100%', objectFit: 'cover' }
            }),
            el('div', { className: 'inner-banner-overlay' },
                el('div', { ref: bannerTextRef, style: { width: '100%', textAlign: 'center' } },
                    el(AppleTextReveal, { text: card.title, style: { color: '#fff', marginBottom: '1rem' } }),
                    el(Reveal, { animation: 'fade-up', delay: 300 },
                        el('p', { className: 'inner-banner-subtitle', style: { color: 'rgba(255,255,255,0.8)' } }, 'Explore the full story below.')
                    )
                )
            )
        ),
        el('div', { className: 'inner-content' },
            el(Reveal, { animation: 'fade-up' }, el('p', { className: 'inner-description' }, card.description)),
            el(Reveal, { animation: 'fade-up', delay: 150 }, el('p', { className: 'inner-description' }, 'We focus on capturing every feeling.')),

            el('div', { className: 'masonry-grid' },
                galleryImages.map((src, idx) => {
                    const itemContent = el('div', {
                        className: `masonry-item ${idx % 2 === 0 ? 'portrait' : 'landscape'}`,
                        onClick: () => setActiveImageIndex(idx),
                        style: { cursor: 'pointer' }
                    },
                        el('img', {
                            src: src,
                            alt: `Gallery image ${idx + 1}`,
                            loading: 'eager', // Force instant load
                            fetchpriority: idx < 8 ? 'high' : 'auto',
                            decoding: 'sync', // Decode immediately
                            style: { display: 'block', width: '100%', minHeight: '100px' }
                        })
                    );

                    // Top items appear instantly (0s). Deep items reveal on scroll.
                    if (idx < 8) {
                        return el('div', { key: idx }, itemContent);
                    }
                    return el(Reveal, { key: idx, animation: 'fade-up', delay: (idx % 6) * 80 }, itemContent);
                })
            ),
            el(BookShootCTA, { titlePart2: ` to book your ${card.title.toLowerCase()}?` })
        ),
        activeImageIndex !== null && el(Lightbox, {
            images: galleryImages,
            activeIndex: activeImageIndex,
            onClose: () => setActiveImageIndex(null),
            onNext: () => setActiveImageIndex((prev) => (prev + 1) % galleryImages.length),
            onPrev: () => setActiveImageIndex((prev) => (prev - 1 + galleryImages.length) % galleryImages.length)
        })
    );
}
